    [Route("api/[controller]")]
    [Authorize(Policy = "JobFileUpload")]
    public class TranslationController : ControllerBase
    {
        private readonly IFileStorageService _fileStorageService;
        private readonly ILogger<TranslationController> _logger;

        public TranslationController(IFileStorageService fileStorageService, ILogger<TranslationController> logger)
        {
            _fileStorageService = fileStorageService;
            _logger = logger;
        }

        // Policy setup: Add policy "JobFileUpload" for this endpoint as well.
        [HttpPost("upload")]
        [Authorize(Policy = "JobFileUpload")]
        [ValidateAntiForgeryToken]
        public async Task<IActionResult> UploadDeliverables([FromForm] UploadDeliverableDto uploadDto)
        {
            try
            {
                if (!ModelState.IsValid)
                {
                    _logger.LogWarning("Upload validation failed: {Errors}", ModelState.Values.SelectMany(v => v.Errors).Select(e => e.ErrorMessage));
                    return BadRequest(new { error = "Invalid input", details = ModelState.Values.SelectMany(v => v.Errors).Select(e => e.ErrorMessage) });
                }

                if (uploadDto.File == null || uploadDto.File.Length == 0)
                {
                    _logger.LogWarning("No file provided for jobId {JobId}", uploadDto.JobId);
                    return BadRequest(new { error = "No file uploaded." });
                }

                var result = await _fileStorageService.SaveJobDeliverableAsync(uploadDto.JobId, uploadDto.OutputName, uploadDto.File);

                if (!result.Success)
                {
                    _logger.LogWarning("File save failed for jobId {JobId}: {Reason}", uploadDto.JobId, result.ErrorMessage);
                    return BadRequest(new { error = result.ErrorMessage });
                }

                _logger.LogInformation("File uploaded successfully for jobId {JobId}, outputName {OutputName}", uploadDto.JobId, uploadDto.OutputName);
                return Ok(new { message = "File uploaded successfully." });
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected error during file upload for jobId {JobId}", uploadDto.JobId);
                return StatusCode(500, new { error = "Internal server error." });
            }
        }
    }
