// Services/FileStorageService.cs
using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace YourAppNamespace.Services
{
    public class FileStorageService : IFileStorageService
    {
        private static readonly HashSet<string> AllowedExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            ".pdf", ".docx", ".xlsx", ".txt", ".csv", ".pptx", ".json"
        };

        private static readonly Dictionary<string, byte[]> AllowedFileSignatures = new Dictionary<string, byte[]>
        {
            [".pdf"] = new byte[] { 0x25, 0x50, 0x44, 0x46 },           // %PDF
            [".docx"] = new byte[] { 0x50, 0x4b, 0x03, 0x04 },          // PK.. (zip based)
            [".xlsx"] = new byte[] { 0x50, 0x4b, 0x03, 0x04 },          // PK.. (zip based)
            [".pptx"] = new byte[] { 0x50, 0x4b, 0x03, 0x04 },          // PK.. (zip based)
            [".txt"] = new byte[] { },                                  // No specific signature
            [".csv"] = new byte[] { },                                  // No specific signature
            [".json"] = new byte[] { },                                 // No specific signature
        };

        private readonly string _baseStoragePath;
        private readonly ILogger<FileStorageService> _logger;

        public FileStorageService(IConfiguration configuration, ILogger<FileStorageService> logger)
        {
            _baseStoragePath = configuration.GetValue<string>("Storage:JobDeliverablesPath") ?? Path.Combine(AppContext.BaseDirectory, "storage", "jobs");
            _logger = logger;
        }

        public async Task<FileSaveResult> SaveJobDeliverableAsync(string jobId, string outputName, IFormFile file)
        {
            try
            {
                // Validate extension and filename
                var extension = Path.GetExtension(outputName);
                if (string.IsNullOrWhiteSpace(extension) || !AllowedExtensions.Contains(extension))
                {
                    return FileSaveResult.Failed("File type not allowed.");
                }

                if (!IsValidFileName(outputName))
                {
                    return FileSaveResult.Failed("Invalid output file name.");
                }

                if (file.Length > 10 * 1024 * 1024)
                {
                    return FileSaveResult.Failed("File size exceeds 10 MB limit.");
                }

                // Verify file signature for allowed types with known signatures
                if (AllowedFileSignatures.TryGetValue(extension, out var expectedSignature) && expectedSignature.Length > 0)
                {
                    using (var sigStream = file.OpenReadStream())
                    {
                        var actualSignature = new byte[expectedSignature.Length];
                        var read = await sigStream.ReadAsync(actualSignature, 0, expectedSignature.Length);
                        if (read != expectedSignature.Length || !actualSignature.SequenceEqual(expectedSignature))
                        {
                            return FileSaveResult.Failed("File signature does not match file type.");
                        }
                    }
                }

                var safeFileName = GenerateSafeFileName(outputName);

                var jobDirectory = Path.Combine(_baseStoragePath, jobId);
                Directory.CreateDirectory(jobDirectory);

                var filePath = Path.Combine(jobDirectory, safeFileName);

                // Never overwrite existing files
                if (File.Exists(filePath))
                {
                    return FileSaveResult.Failed("A file with the same name already exists.");
                }

                using (var fileStream = new FileStream(filePath, FileMode.CreateNew, FileAccess.Write, FileShare.None, 4096, useAsync: true))
                {
                    await file.CopyToAsync(fileStream);
                }

                // Set least-privilege file permissions if on Linux/Unix
                try
                {
                    if (OperatingSystem.IsLinux() || OperatingSystem.IsMacOS())
                    {
                        // Remove all execution permissions
                        UnixFilePermissionHelper.SetFilePermissions(filePath, "rw-------");
                    }
                }
                catch (Exception ex)
                {
                    _logger.LogWarning(ex, "Could not set file permissions for {Path}", filePath);
                }

                // Optionally: trigger scanning/quarantine logic here

                return FileSaveResult.Success();
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Error saving file for jobId {JobId}, outputName {OutputName}", jobId, outputName);
                return FileSaveResult.Failed("Failed to save file.");
            }
        }

        private static bool IsValidFileName(string fileName)
        {
            if (string.IsNullOrWhiteSpace(fileName) || fileName.Length > 128)
            {
                return false;
            }
            var invalidChars = Path.GetInvalidFileNameChars();
            if (fileName.Any(ch => invalidChars.Contains(ch)))
            {
                return false;
            }
            // Prevent path traversal
            if (fileName.Contains("..") || fileName.Contains("/") || fileName.Contains("\\"))
            {
                return false;
            }
            return true;
        }

        private static string GenerateSafeFileName(string originalName)
        {
            // Remove any dangerous characters, keep only safe chars
            var name = Path.GetFileNameWithoutExtension(originalName);
            var ext = Path.GetExtension(originalName);
            name = Regex.Replace(name, @"[^a-zA-Z0-9_\-]", "_");
            var uniqueSuffix = Guid.NewGuid().ToString("N").Substring(0, 8);
            return $"{name}_{uniqueSuffix}{ext}";
        }
    }
}
