using System.Diagnostics;

namespace YourAppNamespace.Services
{
    public static class UnixFilePermissionHelper
    {
        public static void SetFilePermissions(string filePath, string permissionOctal)
        {
            // permissionOctal: e.g., "600" for rw-------, "644" for rw-r--r--
            var psi = new ProcessStartInfo
            {
                FileName = "/bin/chmod",
                ArgumentList = { permissionOctal, filePath },
                RedirectStandardOutput = true,
                RedirectStandardError = true,
                UseShellExecute = false,
                CreateNoWindow = true
            };
            using (var process = Process.Start(psi))
            {
                process.WaitForExit();
            }
        }
    }
}
